// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // darken (decay) over uTime
    ret *= 0.99; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


// This shader is intended to apply an eight way mirror, generate a normal map, create per-pixel material properties
//    based on pixel color properties (saturation, brightness, etc.) and then a lighting set up with one point light
//    and one environmental light.


 // First we find the average of the x & y for each of our pixels, this lets us test to see which quarter of
 //   the screen we are in when you divide it up from corner to corner.  along the diagonal from 0,0 to 1,1,
 //   x = y, and along the other diagonal, (x + y) / 2 = .5... so we precompute for efficiency:
    float non_ave = float((vUv.x + vUv.y)* 0.5);
    float lat_ave = float((vUv.x + uTexSize.z + vUv.y)* 0.5);
    float vrt_ave = float((vUv.x + vUv.y + uTexSize.w)* 0.5);


 // create 3 vUv pairs; non, for the non-shifted pixel, lat, for the pixel shifted in x and vrt for the y-shifted one
    vec2 non_final = vUv;
    vec2 lat_final = vec2(vUv.x + uTexSize.z, vUv.y);
    vec2 vrt_final = vec2(vUv.x, vUv.y + uTexSize.w);


 // Now we flip and flop each of our three uvs around to give us a total of 8 possible uvs per pixel
    vec2 non_one = non_final.yx;
    vec2 lat_one = lat_final.yx;
    vec2 vrt_one = vrt_final.yx;
    vec2 non_two = non_one * vec2(-1, 1);
    vec2 lat_two = lat_one * vec2(-1, 1);
    vec2 vrt_two = vrt_one * vec2(-1, 1);
    vec2 non_three = non_two.yx;
    vec2 lat_three = lat_two.yx;
    vec2 vrt_three = vrt_two.yx;
    vec2 non_four = non_three * vec2(-1, 1);
    vec2 lat_four = lat_three * vec2(-1, 1);
    vec2 vrt_four = vrt_three * vec2(-1, 1);
    vec2 non_five = non_four.yx;
    vec2 lat_five = lat_four.yx;
    vec2 vrt_five = vrt_four.yx;
    vec2 non_six = non_five * vec2(-1, 1);
    vec2 lat_six = lat_five * vec2(-1, 1);
    vec2 vrt_six = vrt_five * vec2(-1, 1);
    vec2 non_seven = non_six.yx;
    vec2 lat_seven = lat_six.yx;
    vec2 vrt_seven = vrt_six.yx;


 // Next we decide which of our 24 uvs we should use for each of our 3 pixels
    if (non_ave < 0.5 && non_final.x < 0.5 && non_final.y < 0.5 && non_final.x < non_final.y){non_final = non_one;}
    if (lat_ave < 0.5 && lat_final.x < 0.5 && lat_final.y < 0.5 && lat_final.x < lat_final.y){lat_final = lat_one;}
    if (vrt_ave < 0.5 && vrt_final.x < 0.5 && vrt_final.y < 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_one;}
    if (non_ave < 0.5 && non_final.x < 0.5 && non_final.y > 0.5 && non_final.x < non_final.y){non_final = non_two;}
    if (lat_ave < 0.5 && lat_final.x < 0.5 && lat_final.y > 0.5 && lat_final.x < lat_final.y){lat_final = lat_two;}
    if (vrt_ave < 0.5 && vrt_final.x < 0.5 && vrt_final.y > 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_two;}
    if (non_ave > 0.5 && non_final.x < 0.5 && non_final.y > 0.5 && non_final.x < non_final.y){non_final = non_three;}
    if (lat_ave > 0.5 && lat_final.x < 0.5 && lat_final.y > 0.5 && lat_final.x < lat_final.y){lat_final = lat_three;}
    if (vrt_ave > 0.5 && vrt_final.x < 0.5 && vrt_final.y > 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_three;}
    if (non_ave > 0.5 && non_final.x > 0.5 && non_final.y > 0.5 && non_final.x < non_final.y){non_final = non_four;}
    if (lat_ave > 0.5 && lat_final.x > 0.5 && lat_final.y > 0.5 && lat_final.x < lat_final.y){lat_final = lat_four;}
    if (vrt_ave > 0.5 && vrt_final.x > 0.5 && vrt_final.y > 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_four;}
    if (non_ave > 0.5 && non_final.x > 0.5 && non_final.y > 0.5 && non_final.x > non_final.y){non_final = non_five;}
    if (lat_ave > 0.5 && lat_final.x > 0.5 && lat_final.y > 0.5 && lat_final.x > lat_final.y){lat_final = lat_five;}
    if (vrt_ave > 0.5 && vrt_final.x > 0.5 && vrt_final.y > 0.5 && vrt_final.x > vrt_final.y){vrt_final = vrt_five;}
    if (non_ave > 0.5 && non_final.x > 0.5 && non_final.y < 0.5 && non_final.x > non_final.y){non_final = non_six;}
    if (lat_ave > 0.5 && lat_final.x > 0.5 && lat_final.y < 0.5 && lat_final.x > lat_final.y){lat_final = lat_six;}
    if (vrt_ave > 0.5 && vrt_final.x > 0.5 && vrt_final.y < 0.5 && vrt_final.x > vrt_final.y){vrt_final = vrt_six;}
    if (non_ave < 0.5 && non_final.x > 0.5 && non_final.y < 0.5 && non_final.x > non_final.y){non_final = non_seven;}
    if (lat_ave < 0.5 && lat_final.x > 0.5 && lat_final.y < 0.5 && lat_final.x > lat_final.y){lat_final = lat_seven;}
    if (vrt_ave < 0.5 && vrt_final.x > 0.5 && vrt_final.y < 0.5 && vrt_final.x > vrt_final.y){vrt_final = vrt_seven;}

// Then we get our three pixels
    vec3 non = texture(sampler_main, non_final).xyz;
    vec3 lat = texture(sampler_main, lat_final).xyz;
    vec3 vrt = texture(sampler_main, vrt_final).xyz;

// Get the heights of each of the pixels and generate the vector from 0,0 to our main pixel
    float steepen = 1.50;
    float nonHeight = float(lum(non)*steepen);
    float latHeight = float(lum(lat)*steepen);
    float vrtHeight = float(lum(vrt)*steepen);
    vec3 vecToTex = vec3(non_final.x * uTexSize.x, non_final.y * uTexSize.y, nonHeight);//derived from vUv & luminosity of texel

// Use the 3 pixels heights to generate the surface normal
    vec3 normal = vec3((nonHeight - latHeight), nonHeight - vrtHeight, 0.0);
    float normalLen = length(normal);
    normal = ((normalLen > 1.0) * (normal * (1.0 / normalLen)) + ((normalLen <= 1.0) * normal));
    normal.z = sqrt(1 - (pow(normal.x, 2) + pow(normal.y, 2)));
    normal = ((normalLen > 1.0) * (normal * (1.0 / normalLen)) + ((normalLen <= 1.0) * normal));
    vec3 dspNormal = (normal + 1.0)*0.5;


//Pulling the color characteristics of this pixel
  //Sorting our color chanels by their values
    float brightest = 0.00;    float middle = 0.00;    float dimmest = 0.00;
    if(non.x >= non.y && non.y >= non.z){brightest = non.x;    middle = non.y;    dimmest = non.z;}
    if(non.x >= non.z && non.z >  non.y){brightest = non.x;    middle = non.z;    dimmest = non.y;}
    if(non.z > non.x  && non.x >  non.y){brightest = non.z;    middle = non.x;    dimmest = non.y;}
    if(non.z >= non.y && non.y >= non.x){brightest = non.z;    middle = non.y;    dimmest = non.x;}
    if(non.y > non.z  && non.z >  non.x){brightest = non.y;    middle = non.z;    dimmest = non.x;}
    if(non.y > non.x  && non.x >= non.z){brightest = non.y;    middle = non.x;    dimmest = non.z;}
    if(non.x == non.y && non.y == non.z){brightest = non.x;    middle = non.y;    dimmest = non.z;}

  //Determining the characteristics
    float saturation = brightest - dimmest;  //0.0 = grey-scale ... 1.0 = primary or complimentary color
    float complimentary = middle - dimmest;  //0.0 = grey-scale or primary ... 1.0 complimentary
    float primary = saturation - complimentary;
    float lightness = (brightest + dimmest) * 0.4;
    float pastelles = (1 - lightness) - saturation;
  //

    non = ((complimentary * non * q28) + (primary * non * q22) + (pastelles * non * q25)) * 3.0;


  //
    float hardness = min((saturation * lightness + 0.001),0.85); //how pollished is the surface
    float opacity = 1.0; //how transparent is this material
    vec3 transColor = vec3(1.0, 1.0, 1.0); //color of light that the material lets pass through itself

//  so as to give the aproximate location of the viewers head.
    vec3 vecToCam = vec3(0.5 * q10, 0.50 * q11, 1.15 * q10);//Where's your head at in screen coordinate space?
    vecToCam = vecToCam - vecToTex;//vector fom texel to your head in pixels
    vecToCam = normalize(vecToCam);

// Point Light--Get the Point Light vector and color data, then use data to get point light color.
    vec3 vecToPtL = vec3((q1 * q12), (q2 * q13), (q3 * q12));  //provided in per uFrame
    vecToPtL = vecToPtL - vecToTex;  //make vector relative to this texel
    float vTPLLength = sqrt(pow(vecToPtL.x,2)+pow(vecToPtL.y,2)+pow(vecToPtL.z,2));
    vecToPtL = normalize(vecToPtL);  //normalize
    vec3 PtLColor = vec3(q4, q5, q6);

// Environment Light--Using q7 = phi & q8 = theta to get the vector to the Environmental Light
    float z = sin(q8);  float n = cos(q8);  float y = sin(q7) * n;  float x = cos(q7) * n;
    vec3 vecToEnL = vec3(x,y,z);//calculate from phi & theta
    vec3 EnLColor = vec3(q9, q10, q11);//use ColorLUT




//=======================>>>>>>>>>>> Generate Lighting <<<<<<<<<<<<======================
//---------------------------------------------------------------------------------------
//***********TODO2: lay in material properties equations on both lights

// Generate the Environmental light contribution
    float EnLAngularFactor = (nonHeight > 0.0) * min(max(dot(normal,vecToEnL),0.002),1.0);
    vec3 EnLContrib = pow(1.7 * EnLAngularFactor, 2) * EnLColor * non;

// Generate Environmental light specular highlights
    vec3 EnLSpecVec = vec3(250 * vecToEnL.x + vecToCam.x, 250 * vecToEnL.y + vecToCam.y, 250 * vecToEnL.z + vecToCam.z);
    EnLSpecVec = normalize(EnLSpecVec);
    float EnLSAngFact = max(0.0, dot(EnLSpecVec, normal));
    EnLSAngFact = pow((1 - sqrt(1 - pow(EnLSAngFact, 2))) * (nonHeight > 0.0), 1.0 + (hardness * 255));
    EnLContrib = mix(EnLContrib, EnLColor, EnLSAngFact);

// Generate point light contribution
    float PtLAngularFactor = (nonHeight > 0.0) * min(max(dot(normal, vecToPtL),0.00),1.0);
    float brightness = q5;//***********TODO4: rework point light falloff
    float factor = (1.0 - brightness) * 0.01805;
    float falloff = 0.01805 + max(0,(1.0 - (vTPLLength * (0.000075 + factor))));//brightness of 1 = 0.00025 0 = 0.0183 gives a ranging factor of 0.01805
    vec3 PtLContrib = (PtLAngularFactor * falloff) * PtLColor * non;

// Generate point lights specular highlight
    vec3 PtLSpecVec = vec3(vecToPtL.x + vecToCam.x, vecToPtL.y + vecToCam.y, vecToPtL.z + vecToCam.z);
    PtLSpecVec = normalize(PtLSpecVec);
    float PtLSAngFact = max(0.0, dot(PtLSpecVec, normal));
    PtLSAngFact = pow((1 - sqrt(1 - pow(PtLSAngFact, 2))) * (nonHeight > 0.0), 1.0 + (hardness * 255));
    PtLContrib = mix(PtLContrib, min(PtLColor * q5, 1.0), PtLSAngFact);
ret = PtLContrib + EnLContrib;//(vec3(1,1,1)*(brightest))*Bri;//dspNormal;//PtLAngularFactor * falloff;//non;//EnLContrib;//norm;//EnLAngularFactor;// distToPtL;// vec3(vUv.x, vUv.y, normHeight);//
//ret = PtLSAngFact; //(1 + PtLSpecVec) * 0.5;


  fragColor = ret;
}
